import React,{useEffect, useState} from 'react'
import AOS from 'aos'
import photo from '../Img/photo.jpeg'
import upiita from '../Img/upiita.png'

const AboutMe = () => {

    const [finished,setFinished] = useState(true)

    useEffect(()=>{
        if( navigator.userAgent.match(/Android/i) || navigator.userAgent.match(/webOS/i) || navigator.userAgent.match(/iPhone/i) || navigator.userAgent.match(/iPad/i) || navigator.userAgent.match(/iPod/i) || navigator.userAgent.match(/BlackBerry/i) || navigator.userAgent.match(/Windows Phone/i)){
            setFinished(false)
        }else{
            setFinished(true)
        }
    },[finished])


    useEffect(()=>{
        AOS.init({
            delay: 500,
            duration: 2000,
            offset: 120,
            easing: 'ease'
        })
    },[])

    if(finished){
        return(
            <div className="About">
                <div className="About-Me">
                    <div className="About-Me-Text" data-aos="zoom-in-right">
                        <p className="About-Me-Text-Name">René morgado</p>
                        <p className="About-Me-Text-More">Desarrollador frontend</p>
                        <p className="About-Me-Text-More">20 Años, CDMX</p>
                    </div>
                    <div className="About-Me-Photo" data-aos="zoom-in-left">
                        <img src={photo} alt="René Morgado"/>
                    </div>
                </div>
                <div className="About-School">
                    <div className="About-School-Text" >
                        <p className="About-School-Text-Info">Soy estudiante de Ingeniería en Telemática en la Unidad Profesional Interdisciplinaria en Ingeniería y Tecnologías Avanzadas del Instituto Politécnico Nacional, además de estudiante activo en Platzi y Udemy.</p>
                    </div>
                    <div className="About-School-Photo" >
                        <img src={upiita} alt="Upiita"/>
                    </div>
                </div>
                <div className="About-Job">
                    <div className="About-Job-Text" >
                        <p className="About-Job-Text-Info">Actualmente laboro como empleado externo en BBVA por parte de la consultora <a rel="noreferrer" href="https://sitdigital.team" target="_blank"> SitDigital</a>, con desarrollos en la banca móvil para PYMES y la App BBVA. </p>
                        <p className="About-Job-Text-Info">Además, participo voluntariamente en los desarrollos de la empresa <a rel="noreferrer" href="https://isia.com.mx" target="_blank"> ISIA México</a> para liberar créditos escolares.</p>
                        <p className="About-Job-Text-Info">Manejo las siguientes herramientas: </p>
                    </div>
                    <div className="About-Job-Tools">

                    </div>
                </div>
            </div>
        )
    }else{
        return (
            <div className="Working">
                <p className="Working-Title">
                    Página en construcción
                </p>
                <p className="Working-Subtitle">
                    Se está creando una nueva experiencia para ti
                </p>
                <i className="fas fa-spinner Working-Icon"></i>
            </div>
        )
    }
}

export default AboutMe
