import React from 'react'
import { Link, useHistory } from 'react-router-dom'
import logo from '../Img/logo.png'

const Frame = ({children}) => {

    const history = useHistory()

    const _goToIndex = () => {
        history.push('/')
    }

    return (
        <div className="Frame">
            <div className="Frame-Logo">
                <img onClick={_goToIndex} className="Frame-Logo-Img" src={logo} alt="Rene Morgado" />
            </div>
            <div className="Frame-Links">
                <Link className="Frame-Links-Link" to="/aboutme">¿Quién soy?</Link>
                <Link className="Frame-Links-Link" to="/projects">Proyectos</Link>
                <Link className="Frame-Links-Link" to="/contact">Contacto</Link>
            </div>
            <div className="Frame-Content">
                {children}
            </div>
            <div className="Frame-Social">
                <a className="Frame-Social-Link" href="/"><i className="fab fa-instagram"></i></a>
                <a className="Frame-Social-Link" href="/"><i className="fab fa-github-square"></i></a>
                <a className="Frame-Social-Link" href="/"><i className="fab fa-linkedin"></i></a>
            </div>
        </div>
    )
}

export default Frame
